DELETE FROM flashcards        WHERE module_id='c1000013-0000-0000-0000-000000000013' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000013-0000-0000-0000-000000000013' AND created_by='buildout:m19';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A topographic survey records both planimetric features and relief (elevations) of existing ground tied to horizontal and vertical control','Grid, radial (radiation), and cross-section are the three classic field methods; modern total station/GNSS work is usually radial','Point density and feature selection are driven by the intended map scale and contour interval','Every detail point is located from established control, never from another detail point']::text[], learning_objectives=ARRAY['Define a topographic survey and distinguish planimetric from relief (vertical) detail','Compare the grid, radial (radiation), and cross-section methods of topographic data collection','Select an appropriate method and point density for a given site and intended map scale','Explain how control underpins every topographic survey and how detail points are tied to it']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='f154fdbd-1aec-4c41-a6a8-a7f67b40a53a';
DELETE FROM lesson_blocks WHERE lesson_id='f154fdbd-1aec-4c41-a6a8-a7f67b40a53a';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A contour is a line of constant elevation; the contour interval is the vertical distance between adjacent contours','Contours never cross or split, close on themselves, and are spaced close on steep ground and far apart on flat ground','Elevation between two known points interpolates linearly: e = eA + (eB − eA)·d/D','Number of contours between two elevations = floor of the elevation difference divided by the interval']::text[], learning_objectives=ARRAY['Define a contour line and contour interval and state the basic properties of contours','Interpret terrain from contour patterns: slope, ridges, valleys, summits, depressions, and saddles','Linearly interpolate the elevation of a point between two known elevations by proportional distance','Estimate how many contour lines fall between two elevations for a given interval']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='99ca2a92-e87b-493f-bb7c-1cae6d4dd950';
DELETE FROM lesson_blocks WHERE lesson_id='99ca2a92-e87b-493f-bb7c-1cae6d4dd950';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A DTM/DEM is a digital representation of the ground surface from which contours, profiles, slopes, and volumes are derived','A DEM is usually a regular raster grid of elevations; a TIN is an irregular triangular mesh of measured points','A DTM is bare-earth terrain; a DSM (digital surface model) includes buildings and vegetation','Breaklines force the surface to bend along linear grade breaks (ridges, ditches, edges) so the model honors real terrain']::text[], learning_objectives=ARRAY['Define DTM, DEM, and DSM and distinguish bare-earth from first-surface models','Describe the TIN and raster-grid structures used to represent a surface','Explain the role of breaklines in forcing a model to honor grade breaks','Identify products derived from a surface model: contours, profiles, slopes, and volumes']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='09a9602d-40c0-42c4-a2ad-bba213dcc715';
DELETE FROM lesson_blocks WHERE lesson_id='09a9602d-40c0-42c4-a2ad-bba213dcc715';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Total station, GNSS RTK, LiDAR, and UAS are the core topographic data-collection technologies, each with a niche','GNSS RTK is fast in the open but needs sky view; total stations excel under canopy and for tight relative accuracy','LiDAR and UAS capture mass points over large or hazardous areas, producing dense point clouds','Feature codes and line-work codes attached in the field let software draw the map automatically, so coding discipline is essential']::text[], learning_objectives=ARRAY['Describe the principal data-collection technologies: total station, GNSS RTK, terrestrial/mobile LiDAR, and UAS','Match each technology to appropriate site conditions, accuracy, and productivity','Explain feature (descriptor) codes and line-work codes that turn raw shots into a drawing','State good field practice for codes, attributes, and the survey-to-CAD workflow']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='384ced07-ed6b-46b9-88b7-b262a9524398';
DELETE FROM lesson_blocks WHERE lesson_id='384ced07-ed6b-46b9-88b7-b262a9524398';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Map scale is the ratio of map distance to ground distance; large scale = small area, more detail','Map distance (in.) = ground distance (ft) × 12 ÷ scale denominator, when scale is 1 in. = denominator ft','Every map needs title, scale (ratio + graphic bar), north arrow, legend, datum, and source/date','Symbols and accuracy standards (NMAS, ASPRS Positional Accuracy Standards) make maps consistent and verifiable']::text[], learning_objectives=ARRAY['Explain map scale (ratio, engineer''s, and graphic) and convert ground distance to map distance','Distinguish large-scale from small-scale maps and relate scale to detail and coverage','Identify the standard elements every map must carry (title, scale, north arrow, legend, datum)','Read common topographic symbols and state mapping accuracy standards (e.g., NMAS / ASPRS)']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='be27f689-8827-43fc-8fdd-f015d2d8b369';
DELETE FROM lesson_blocks WHERE lesson_id='be27f689-8827-43fc-8fdd-f015d2d8b369';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A GIS stores, analyzes, and displays spatial data as layers of geometry plus attributes, in vector and raster form','Surveyors are the authoritative source of accurate, control-tied geometry that GIS layers depend on','All layers must share a common datum, coordinate system, and projection to overlay correctly','Metadata, documented accuracy, and clean attributes are what make survey data usable and trusted in a GIS']::text[], learning_objectives=ARRAY['Define GIS and distinguish vector and raster spatial data and their attributes','Explain the surveyor''s role in supplying authoritative, accurate spatial data to a GIS','Describe coordinate systems, datums, and projections and why they must match across datasets','Recognize metadata, accuracy, and the survey-to-GIS handoff in modern geospatial practice']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='4c291d33-27fd-44ec-aa26-a2af9ed63b8b';
DELETE FROM lesson_blocks WHERE lesson_id='4c291d33-27fd-44ec-aa26-a2af9ed63b8b';
  'eeee1950-0000-0000-0000-000000000001', 'Contour interpolation — elevation between two known points', 'Compute the elevation of a point lying between two known elevations by linear (proportional-distance) interpolation.', 'Topographic & Mapping — Contours', 'Interpolation', 'numeric_input', 'medium', 'Point A has elevation {{eA:f2}} ft and point B has elevation {{eB:f2}} ft. The horizontal distance from A to B is {{D}} ft. Assuming a uniform slope, what is the elevation (ft) of a point located {{d}} ft from A toward B?', 'eA + (eB - eA)*d/D', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"eA","type":"float","min":500,"max":700,"decimals":2},{"name":"rise","type":"float","min":4,"max":20,"decimals":2},{"name":"D","type":"integer","min":60,"max":150},{"name":"frac","type":"float","min":0.2,"max":0.8,"decimals":2}]'::jsonb, '[{"name":"eB","formula":"round(eA + rise,2)"},{"name":"d","formula":"round(D*frac,0)"}]'::jsonb, '[{"step_number":1,"title":"Elevation difference","formula":"eB − eA","calculation_template":"{{eB:f2}} − {{eA:f2}}"},{"step_number":2,"title":"Proportional distance","formula":"d ÷ D","calculation_template":"{{d}} ÷ {{D}}"},{"step_number":3,"title":"Interpolated elevation","result_template":"e = {{eA:f2}} + ({{eB:f2}} − {{eA:f2}}) × {{d}} ÷ {{D}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear interpolation: e = eA + (eB − eA)·d/D = {{eA:f2}} + ({{eB:f2}} − {{eA:f2}}) × {{d}} ÷ {{D}} = {{_answer}} ft.', 'c1000013-0000-0000-0000-000000000013', ARRAY['buildout','module-19','practice']::text[], true, 'buildout:m19');
  'eeee1950-0000-0000-0000-000000000002', 'Number of contour lines between two elevations', 'Determine how many whole contour lines fall between a low and a high elevation for a given contour interval.', 'Topographic & Mapping — Contours', 'Contour counting', 'numeric_input', 'easy', 'A slope rises from an elevation of {{eLow}} ft to {{eHigh}} ft. If the contour interval is {{interval}} ft, how many contour lines are crossed between these two elevations?', 'floor((eHigh - eLow)/interval)', '{"decimals":0,"unit":"contours","tolerance":0}', '[{"name":"eLow","type":"integer","min":600,"max":680},{"name":"diff","type":"integer","min":20,"max":90},{"name":"interval","type":"choice","choices":[2,5,10]}]'::jsonb, '[{"name":"eHigh","formula":"eLow + diff"}]'::jsonb, '[{"step_number":1,"title":"Elevation difference","formula":"eHigh − eLow","calculation_template":"{{eHigh}} − {{eLow}}"},{"step_number":2,"title":"Divide by interval and take the floor","result_template":"floor(({{eHigh}} − {{eLow}}) ÷ {{interval}}) = {{_answer}} contours"}]'::jsonb, '{"method":"none"}'::jsonb, 'n = floor((eHigh − eLow)/interval) = floor(({{eHigh}} − {{eLow}}) ÷ {{interval}}) = {{_answer}} contour lines.', 'c1000013-0000-0000-0000-000000000013', ARRAY['buildout','module-19','practice']::text[], true, 'buildout:m19');
  'eeee1950-0000-0000-0000-000000000003', 'Map distance from ground distance and scale', 'Compute the plotted map distance (inches) for a ground distance at a given engineer''s scale of 1 in. = S ft.', 'Topographic & Mapping — Scale', 'Scale conversion', 'numeric_input', 'easy', 'A map is drawn at an engineer''s scale of 1 in. = {{scale}} ft. What is the plotted map distance (inches) for a ground distance of {{groundDist}} ft?', 'groundDist*12/scale', '{"decimals":2,"unit":"in","tolerance":0.02}', '[{"name":"scale","type":"choice","choices":[20,30,40,50,100,200]},{"name":"groundDist","type":"integer","min":100,"max":1200}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Convert ground feet to inches","formula":"groundDist × 12","calculation_template":"{{groundDist}} × 12"},{"step_number":2,"title":"Divide by the scale denominator","result_template":"({{groundDist}} × 12) ÷ {{scale}} = {{_answer}} in."}]'::jsonb, '{"method":"none"}'::jsonb, 'Map distance (in.) = ground distance (ft) × 12 ÷ scale = {{groundDist}} × 12 ÷ {{scale}} = {{_answer}} in.', 'c1000013-0000-0000-0000-000000000013', ARRAY['buildout','module-19','practice']::text[], true, 'buildout:m19');
COMMIT;
