INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000000', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'text', '{"html":"<h3>What a topographic survey records</h3><p>A <strong>topographic survey</strong> measures and maps the existing surface of the ground &mdash; both its <strong>planimetric</strong> features (the horizontal position of natural and man-made objects: buildings, roads, fences, streams, trees, utilities) and its <strong>relief</strong> (the shape of the terrain, expressed by elevations and ultimately by contours). Unlike a boundary survey, whose product is property lines, the topographic survey&rsquo;s product is a picture of <em>what is there</em>: a base map for design, drainage analysis, earthwork, and permitting. It answers the engineer&rsquo;s first question on any site &mdash; how high, how steep, and what is in the way.</p><p>Every topographic survey rests on <strong>control</strong>. The surveyor first establishes (or recovers) horizontal and vertical control monuments of known coordinates and elevation, then locates the thousands of <strong>detail points</strong> &mdash; ground shots and feature shots &mdash; relative to that control. Detail points are always tied to control, never chained from one detail point to the next, so that no error accumulates across the map. The density and selection of those points is governed by the <strong>intended map scale and contour interval</strong>: a 1&deg;=20 ft site plan with a 1-ft interval demands far tighter shots than a 1&deg;=200 ft corridor map at 5-ft contours.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000001', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'text', '{"html":"<h3>The grid method</h3><p>In the <strong>grid method</strong> the area is divided into a regular pattern of squares (for example, a 25-ft or 50-ft grid) staked or stationed on the ground, and an elevation is read at every grid intersection (and at significant grade breaks between them). The grid gives an even, predictable distribution of elevations that is ideal for <strong>interpolating contours</strong> and for computing earthwork volumes by the grid (borrow-pit) method. It works best on <strong>open, relatively uniform ground</strong> where the regular spacing captures the surface well. Its weakness is that a rigid grid can miss abrupt features &mdash; a ditch, ridge, or wall that falls between grid lines &mdash; unless the crew deliberately adds shots at those breaks.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000002', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'text', '{"html":"<h3>The radial (radiation) method</h3><p>The <strong>radial</strong> or <strong>radiation</strong> method locates each detail point by its <strong>direction and distance from an occupied control point</strong> &mdash; the natural mode of a total station or a GNSS rover walking the site. The instrument occupies a control station, and the field crew shoots ground shots and feature shots wherever the terrain or detail requires, recording each as a coordinate (N, E, Z) with a feature code. Radiation is the dominant modern method because it is fast, flexible, and lets the surveyor put shots <em>exactly where the surface needs them</em> &mdash; tops and toes of slopes, edges of pavement, flowlines, grade breaks &mdash; rather than on an arbitrary grid. The resulting point cloud feeds directly into a surface model that generates contours automatically.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000003', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'text', '{"html":"<h3>The cross-section method</h3><p>The <strong>cross-section method</strong> is the method of choice for <strong>linear (corridor) projects</strong> &mdash; roads, channels, pipelines, levees. The surveyor runs a centerline (alignment), establishes <strong>stations</strong> along it, and at each station takes elevations on a line <em>perpendicular</em> to the centerline, recording the offset and elevation of each ground point left and right (at grade breaks and at standard offsets). The data are organized by station and offset, which maps naturally onto roadway design, profile/cross-section sheets, and average-end-area earthwork volume computation. Cross-sectioning concentrates effort along the corridor where the design lives, rather than blanketing a whole area.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000004', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'table', '{"headers":["Method","How points are located","Best suited to"],"rows":[["Grid","Elevation at each node of a regular square grid","Open, fairly uniform sites; grid-volume earthwork"],["Radial (radiation)","Direction + distance from an occupied control point","General topography; total station / GNSS work"],["Cross-section","Offsets & elevations on lines normal to a centerline","Linear corridors: roads, channels, pipelines"],["Photogrammetry / LiDAR / UAS","Mass points from imagery or scanning","Large areas, inaccessible or hazardous terrain"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000005', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'callout', '{"type":"info","text":"Method follows the site. Use radiation for general topo with a total station or GNSS, the grid for open ground and grid-volume work, and cross-sections for corridors. Whatever the method, shoot the grade breaks — a map is only as good as the breaklines that capture the real shape of the surface."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000006', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Three topographic methods over one site — a regular grid, radial shots from a control station, and cross-sections normal to a centerline."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0001-0000-0000-000000000007', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'key_takeaways', '{"title":"Key Takeaways","items":["A topographic survey records planimetric detail plus relief, tied to horizontal and vertical control.","Grid, radial (radiation), and cross-section are the three classic field methods.","Radiation dominates modern total station/GNSS work; cross-sections suit linear corridors.","Map scale and contour interval drive point density and feature selection.","Every detail point is located from control and at the grade breaks — never chained shot-to-shot."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000000', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'text', '{"html":"<h3>What contours are</h3><p>A <strong>contour line</strong> connects points of <em>equal elevation</em> on the ground &mdash; the shoreline a lake would have if its surface stood at that elevation. A topographic map portrays the three-dimensional shape of the land with a family of contours drawn at a fixed vertical spacing called the <strong>contour interval</strong> (for example, every 1 ft, 2 ft, or 5 ft). Every fifth contour is usually drawn heavier and labeled as an <strong>index contour</strong> to aid reading. By studying the pattern of contours, a surveyor or engineer reads slope, drainage, and landform directly from a flat sheet without ever visiting the site.</p><p>The contour interval is chosen for the terrain and the map scale: flat sites and large scales call for a small interval (1 ft) to show subtle relief, while steep or large-area maps use a larger interval (5, 10, or 20 ft) to keep the lines legible. The interval also sets the field accuracy required &mdash; a common rule of thumb holds elevations to roughly one-half the contour interval.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000001', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'text', '{"html":"<h3>Properties of contours</h3><p>Contours follow strict geometric rules that make them readable. They are <strong>continuous</strong> and <strong>close on themselves</strong> (within or beyond the map edge); a contour never simply ends in the middle of a map. Contours <strong>never cross or merge</strong> &mdash; a single ground point cannot have two elevations &mdash; except at a true vertical cliff, where they may appear to touch. Their <strong>spacing reveals slope</strong>: closely spaced contours mean steep ground, widely spaced contours mean gentle ground, and evenly spaced contours mean a uniform slope. Contours <strong>point upstream</strong> as they cross a valley or stream (forming a V whose point heads uphill) and <strong>point downhill</strong> as they cross a ridge (forming a U or V whose nose heads down the spur). A set of <strong>closed contours</strong> with increasing values marks a <strong>summit (hill)</strong>; closed contours with hachure ticks pointing inward, decreasing in value, mark a <strong>depression</strong>. A low point between two summits is a <strong>saddle (pass)</strong>.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000002', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'table', '{"headers":["Contour pattern","Means","How to read it"],"rows":[["Closely spaced","Steep slope","Lines crowd together"],["Widely spaced","Gentle slope","Lines far apart"],["Evenly spaced","Uniform slope","Constant gradient"],["V pointing uphill","Stream / valley","The V points upstream"],["U/V pointing downhill","Ridge / spur","Nose points down the spur"],["Concentric closed loops (rising)","Summit / hill","Highest in the center"],["Closed loops with inward hachures","Depression","Ticks point to the low ground"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000003', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'text', '{"html":"<h3>Interpolating an elevation between two points</h3><p>Maps and surfaces are built by <strong>interpolation</strong> &mdash; estimating elevations between measured points. The standard assumption is a <strong>uniform (linear) slope</strong> between two adjacent known elevations, so elevation varies in direct proportion to distance. If point A has elevation <em>e<sub>A</sub></em> and point B has elevation <em>e<sub>B</sub></em>, and B is a horizontal distance <em>D</em> from A, then the elevation at a point a distance <em>d</em> from A toward B is:</p><p style=\"text-align:center\"><strong>e = e<sub>A</sub> + (e<sub>B</sub> &minus; e<sub>A</sub>) &times; d / D</strong></p><p>For example, if A = 612.0 ft, B = 620.0 ft, the points are 80 ft apart, and we want the elevation 30 ft from A: e = 612.0 + (620.0 &minus; 612.0) &times; 30 / 80 = 612.0 + 8.0 &times; 0.375 = <strong>615.0 ft</strong>. The same proportional reasoning, run the other way, locates <em>where</em> a whole-number contour (say 615 ft) crosses the line between A and B &mdash; the basis of drawing contours by hand from spot elevations.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000004', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'equation', '{"latex":"e = e_A + (e_B - e_A)\\,\\frac{d}{D}","label":"Linear interpolation of elevation between two known points","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000005', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'text', '{"html":"<h3>How many contours between two elevations</h3><p>A quick map-reading skill is counting the contour lines a slope crosses between two elevations. With a contour interval <em>i</em>, the number of contour lines strictly between a low elevation <em>e<sub>low</sub></em> and a high elevation <em>e<sub>high</sub></em> is the whole number of intervals that fit in the elevation difference: <strong>n = floor((e<sub>high</sub> &minus; e<sub>low</sub>) / i)</strong>. For instance, between 643 ft and 678 ft at a 5-ft interval, the difference is 35 ft, so n = floor(35 / 5) = <strong>7</strong> contours (645, 650, 655, 660, 665, 670, 675). The floor function handles the common case where the endpoints are not themselves on whole contours.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000006', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'equation', '{"latex":"n = \\left\\lfloor \\frac{e_{high} - e_{low}}{i} \\right\\rfloor","label":"Number of contour lines between two elevations (interval i)","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000007', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'callout', '{"type":"info","text":"Reading shortcut: contour spacing IS slope. Crowded contours = steep, wide contours = flat. Vs that point uphill are valleys/streams; Vs that point downhill are ridges. Concentric closed loops are a hill — unless they carry inward hachure ticks, which mark a depression."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000008', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Reading landforms from contours — a summit, a stream valley (Vs point upstream), a ridge, and a saddle."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0002-0000-0000-000000000009', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'key_takeaways', '{"title":"Key Takeaways","items":["A contour joins points of equal elevation; the contour interval is the vertical spacing between them.","Contours close on themselves and never cross; spacing shows slope (close = steep, wide = flat).","Vs point upstream in valleys and downhill on ridges; closed loops are summits (hachured = depressions).","Interpolate: e = eA + (eB − eA)·d/D between two known elevations.","Contours between two elevations: n = floor((e_high − e_low)/interval)."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000000', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'text', '{"html":"<h3>From points to a surface</h3><p>Modern topographic mapping does not draw contours directly from field shots; it first builds a <strong>digital surface model</strong> from the points and then derives contours, profiles, slopes, and volumes from that model. A <strong>Digital Terrain Model (DTM)</strong> is a digital representation of the shape of the ground &mdash; the <em>bare earth</em> surface &mdash; commonly enriched with <strong>breaklines</strong> that capture linear features. A <strong>Digital Elevation Model (DEM)</strong> is closely related; in common usage a DEM is specifically a <strong>regular raster grid</strong> of bare-earth elevations (one elevation per cell), while DTM is the broader term for a terrain model that may also carry breaklines and irregular points. A <strong>Digital Surface Model (DSM)</strong>, by contrast, is the <em>first reflective surface</em> &mdash; it includes the tops of buildings, bridges, and tree canopy. Choosing the right model matters: design and drainage use the <strong>bare-earth DTM/DEM</strong>, while a DSM is used for line-of-sight, canopy, and clearance studies.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000001', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'text', '{"html":"<h3>TIN vs. raster grid</h3><p>Two data structures dominate. A <strong>TIN (Triangulated Irregular Network)</strong> connects the measured points themselves into a mesh of non-overlapping triangles (by Delaunay triangulation), so the model passes <em>exactly through</em> every surveyed point and adapts its detail to the data &mdash; dense triangles where shots are close, large triangles where the ground is uniform. A <strong>raster grid (DEM)</strong> resamples the surface onto a regular array of square cells, each holding one elevation. The TIN preserves measured points and breaklines faithfully and is preferred for engineering surfaces; the raster grid is simple, uniform, and ideal for large-area analysis, slope/aspect mapping, and GIS. Many workflows build a TIN from the survey, then export a DEM grid for analysis.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000002', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'table', '{"headers":["Model / structure","What it represents","Typical use"],"rows":[["DTM (terrain)","Bare-earth surface, often with breaklines","Civil design, contours, earthwork"],["DEM (raster grid)","Bare-earth elevation per grid cell","Large-area / GIS analysis, slope & aspect"],["DSM (surface)","First reflective surface (incl. buildings/canopy)","Line-of-sight, clearance, canopy studies"],["TIN","Triangulated mesh through measured points","Engineering surfaces; honors points & breaklines"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000003', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'text', '{"html":"<h3>Breaklines: making the model honor the ground</h3><p>Field shots alone are scattered points; left to a plain triangulation, the surface will cut <em>across</em> a ditch or a curb instead of bending along it, smearing real grade breaks. A <strong>breakline</strong> is a line, supplied with the points, along which the surface is forced to change slope &mdash; the model triangulates <em>along</em> the breakline rather than across it. Breaklines encode the linear features that define terrain shape: <strong>ridges, swales, ditch flowlines, tops and toes of slopes, edges of pavement, walls, and curbs</strong>. A <strong>hard breakline</strong> marks a sharp change in grade (a curb, a ditch bottom); a <strong>soft breakline</strong> enforces a feature without a slope break (e.g., a contour or a planimetric edge). Good breaklines are what separate a correct engineering surface from a smooth but wrong one &mdash; the contours and volumes derived from the model are only as faithful as the breaklines fed into it.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000004', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'callout', '{"type":"info","text":"DEM = bare earth; DSM = first surface (includes buildings and trees). Use the bare-earth model for design and drainage. And remember: a surface without breaklines triangulates straight across ditches and curbs — the breaklines are what make the model bend where the real ground bends."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000005', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'text', '{"html":"<h3>Products derived from a surface model</h3><p>Once a verified surface exists, it becomes the source for nearly every topographic product. <strong>Contours</strong> are generated by intersecting the surface with horizontal planes at the contour interval. <strong>Profiles</strong> (elevation along a line) and <strong>cross-sections</strong> are cut from the model for roadway and channel design. <strong>Slope and aspect</strong> rasters drive drainage and constructability analysis. <strong>Volumes</strong> &mdash; cut and fill between an existing and a proposed surface, or against a datum plane &mdash; are computed directly by comparing surfaces. Because all of these flow from one model, the quality of the model (point density, breaklines, and cleaned outliers) governs the quality of everything downstream.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000006', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A TIN without breaklines smears the ditch; adding breaklines forces the triangulation along the flowline and corrects the surface."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0003-0000-0000-000000000007', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'key_takeaways', '{"title":"Key Takeaways","items":["A DTM/DEM is a digital ground surface from which contours, profiles, slopes, and volumes are derived.","A DEM is usually a regular raster grid; a TIN is an irregular triangular mesh through the measured points.","DTM/DEM are bare earth; a DSM includes buildings and vegetation (first surface).","Breaklines force the surface to bend along ridges, ditches, curbs, and edges — honoring real terrain.","All major topographic products flow from the surface model, so its quality governs everything downstream."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000000', '384ced07-ed6b-46b9-88b7-b262a9524398', 'text', '{"html":"<h3>The data-collection toolkit</h3><p>Topographic data is collected today with a small toolkit of complementary technologies, chosen by site conditions, required accuracy, and productivity. The <strong>total station</strong> measures direction and distance to a prism, giving high relative accuracy and working well <em>under tree canopy and around structures</em> where satellites are blocked. <strong>GNSS RTK (real-time kinematic)</strong> positions a roving receiver in real time against a base or network correction, delivering centimeter-level coordinates very fast in the <em>open sky</em> &mdash; but it degrades or fails under canopy, near tall buildings, and in multipath environments. <strong>LiDAR</strong> (terrestrial, mobile, or airborne laser scanning) sweeps a dense <strong>point cloud</strong> of millions of points over a scene, excellent for complex or hazardous areas. <strong>UAS (drone) mapping</strong> &mdash; photogrammetry or drone-borne LiDAR &mdash; rapidly covers large or inaccessible areas from the air, producing orthophotos and dense surface points tied to ground control.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000001', '384ced07-ed6b-46b9-88b7-b262a9524398', 'table', '{"headers":["Technology","Strength","Limitation"],"rows":[["Total station","High relative accuracy; works under canopy/around buildings","Line of sight to prism; slower point-by-point"],["GNSS RTK","Fast, absolute coords in open sky (cm level)","Needs clear sky view; multipath/canopy degrade it"],["Terrestrial / mobile LiDAR","Dense point cloud; captures complex scenes safely","Large data; occlusions; needs registration to control"],["UAS (drone)","Rapid coverage of large/inaccessible areas","Needs ground control; weather/airspace limits; bare-earth filtering"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000002', '384ced07-ed6b-46b9-88b7-b262a9524398', 'text', '{"html":"<h3>Feature codes: turning shots into a drawing</h3><p>A modern survey collects not just coordinates but <strong>feature codes</strong> (descriptors) on every shot, so the office software can draw the map almost automatically. Each point carries a short <strong>code</strong> identifying what it is &mdash; <code>EP</code> edge of pavement, <code>BC</code> back of curb, <code>FL</code> flowline, <code>TREE</code>, <code>FENCE</code>, <code>MH</code> manhole, <code>SHOT</code> ground shot &mdash; mapped in a <strong>code library (feature-code list)</strong> to a layer, symbol, and attributes. When the data are imported, each coded point lands on the right layer with the right symbol, and the surveyor&rsquo;s plat begins to assemble itself rather than being drafted shot by shot. The code library is the contract between the field and the office: it must be standardized and used consistently for the automation to work.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000003', '384ced07-ed6b-46b9-88b7-b262a9524398', 'text', '{"html":"<h3>Line-work and connectivity codes</h3><p>Beyond identifying point type, codes also build <strong>line work</strong> &mdash; the connected strings that form curbs, edges, fences, and breaklines. Survey software uses <strong>connectivity codes</strong> such as <strong>begin-line / end-line</strong>, <strong>close (PC/PT for curves)</strong>, and <strong>continue</strong>, often with a string number so several lines of the same type can be collected at once (e.g., two curb lines coded <code>BC1</code> and <code>BC2</code>). With these, the same shots that build the planimetric drawing also become <strong>breaklines</strong> in the surface model. Field discipline is everything: a missed begin/end code or a transposed string number produces tangled line work and a wrong surface, so crews are trained to code carefully, add free-form <strong>notes/attributes</strong> (pipe size, sign text, tree species), and review codes before leaving the site.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000004', '384ced07-ed6b-46b9-88b7-b262a9524398', 'callout', '{"type":"info","text":"Code in the field, draft in the office. Consistent feature and line-work codes let software draw layers, symbols, and breaklines automatically. A clean coded dataset is worth far more than thousands of un-coded points — and pick the right tool: RTK in the open, total station under canopy, LiDAR/UAS for mass capture."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000005', '384ced07-ed6b-46b9-88b7-b262a9524398', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Coded field points import into CAD and auto-draw line work, symbols, and layers from the code library."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0004-0000-0000-000000000006', '384ced07-ed6b-46b9-88b7-b262a9524398', 'key_takeaways', '{"title":"Key Takeaways","items":["Total station, GNSS RTK, LiDAR, and UAS are the core topographic collection technologies.","RTK is fast in open sky but needs a clear view; total stations excel under canopy and for tight relative accuracy.","LiDAR and UAS capture dense point clouds over large or hazardous areas, tied to ground control.","Feature codes map each shot to a layer/symbol; line-work codes build strings and breaklines.","Coding discipline in the field is what lets the office auto-draw the map and surface correctly."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000000', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'text', '{"html":"<h3>Map scale</h3><p><strong>Scale</strong> is the relationship between a distance on the map and the corresponding distance on the ground. It is stated three ways. A <strong>representative fraction (ratio)</strong> like 1:1200 means one unit on the map equals 1200 of the same units on the ground. An <strong>engineer&rsquo;s scale</strong> states it in mixed units, e.g. <em>1 in. = 100 ft</em> (which equals 1:1200, since 100 ft = 1200 in.). A <strong>graphic (bar) scale</strong> draws a labeled ruler on the map &mdash; the only form that stays correct when the sheet is photocopied or reduced. A small denominator (1:600) is a <strong>large-scale</strong> map: it covers a small area in fine detail. A large denominator (1:24000) is a <strong>small-scale</strong> map: it covers a large area with less detail. &lsquo;Large scale = large detail, small area&rsquo; is the way to keep it straight.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000001', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'text', '{"html":"<h3>Converting ground distance to map distance</h3><p>For an engineer&rsquo;s scale stated as <em>1 in. = S ft</em> (so the scale denominator is S), a ground distance is reduced to a map distance by converting feet to inches and dividing by the scale denominator:</p><p style=\"text-align:center\"><strong>map distance (in.) = ground distance (ft) &times; 12 / S</strong></p><p>For example, a 450-ft building front drawn at 1 in. = 50 ft plots at 450 &times; 12 / 50 = 5400 / 50 = <strong>9.0 in.</strong> on the sheet. (Equivalently, using a pure ratio 1:R, map distance = ground distance / R in the same units.) The same relation run backward &mdash; ground = map &times; S / 12 &mdash; lets you scale a distance off a paper map. Choosing a scale is a balance: large enough that required detail fits legibly, small enough that the project fits the sheet.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000002', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'equation', '{"latex":"d_{map}(\\text{in.}) = \\frac{d_{ground}(\\text{ft}) \\times 12}{S}\\quad(\\text{scale } 1\\,\\text{in.} = S\\,\\text{ft})","label":"Map distance from ground distance and engineer''s scale","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000003', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'text', '{"html":"<h3>Required map elements</h3><p>A complete, professional map carries a standard set of <strong>marginal information</strong> so it can be read and trusted by anyone. Every map should show a <strong>title / project name and location</strong>; the <strong>scale</strong> (ratio or engineer&rsquo;s scale <em>and</em> a graphic bar scale); a <strong>north arrow</strong> with the basis of bearings (and meridian: true, grid, or magnetic); a <strong>legend</strong> defining the symbols and line types used; the <strong>horizontal and vertical datum</strong> (e.g., NAD83, NAVD88) and coordinate system / zone; the <strong>contour interval</strong>; the <strong>surveyor / firm, date, and source of data</strong>; and, where required, the <strong>surveyor&rsquo;s seal and certification</strong>. Omitting any of these undermines the map&rsquo;s usability and, for a sealed survey, its legal sufficiency.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000004', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'table', '{"headers":["Map element","Why it is required"],"rows":[["Title / location","Identifies the project and area mapped"],["Scale (ratio + graphic bar)","Lets distances be measured; bar survives copying"],["North arrow + basis of bearings","Orientation and meridian (true/grid/magnetic)"],["Legend","Defines symbols and line types"],["Datum & coordinate system","Horizontal/vertical reference (NAD83, NAVD88, zone)"],["Contour interval","States the vertical spacing of contours"],["Surveyor, date, source, seal","Authorship, currency, and legal certification"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000005', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'text', '{"html":"<h3>Symbology and accuracy standards</h3><p>Maps communicate through a shared language of <strong>symbols</strong>: blue for water, green for vegetation, brown contours, black culture (roads, buildings), with conventional point and line symbols for fences, utilities, vegetation, and structures &mdash; defined in the legend and, for federal mapping, in standards like the USGS topographic symbol set. <strong>Mapping accuracy standards</strong> make a map verifiable. The classic <strong>National Map Accuracy Standards (NMAS)</strong> set horizontal and vertical tolerances tied to scale and contour interval (e.g., vertical accuracy such that no more than 10% of tested points err by more than half the contour interval). The modern <strong>ASPRS Positional Accuracy Standards for Digital Geospatial Data</strong> express accuracy directly as RMSE values, independent of a paper scale &mdash; the framework now used for digital orthophotos, LiDAR, and DEMs. Stating the standard a map meets tells the user exactly how much to trust a measured position.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000006', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'callout', '{"type":"info","text":"Keep scale straight: large scale (small denominator like 1:600) shows a small area in fine detail; small scale (1:24000) shows a large area coarsely. And always include a graphic bar scale — it is the only scale form that stays correct after a map is copied or resized."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000007', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A complete map sheet — title, ratio and graphic scales, north arrow, legend, datum, and contour interval."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0005-0000-0000-000000000008', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'key_takeaways', '{"title":"Key Takeaways","items":["Scale relates map to ground distance, stated as a ratio, an engineer''s scale, or a graphic bar.","Map distance (in.) = ground distance (ft) × 12 ÷ scale denominator (for 1 in. = S ft).","Large scale = small area, more detail; small scale = large area, less detail.","Every map needs title, scale (incl. graphic bar), north arrow, legend, datum, contour interval, and certification.","Symbology and accuracy standards (NMAS, ASPRS) make maps consistent, readable, and verifiable."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000000', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'text', '{"html":"<h3>What a GIS is</h3><p>A <strong>Geographic Information System (GIS)</strong> is software and data for capturing, storing, analyzing, and displaying <strong>spatially referenced information</strong>. Its organizing idea is the <strong>layer</strong>: each theme &mdash; parcels, roads, utilities, contours, zoning, soils &mdash; is a separate layer of geographic <em>geometry</em> joined to a table of <em>attributes</em>. Layers stacked in register let an analyst ask spatial questions a paper map cannot: which parcels lie within a floodplain, how many feet of sewer fall under a proposed road, what is within 300 ft of a school. For the surveyor, GIS is both a customer for survey data and a tool that increasingly underlies asset management, planning, and infrastructure across cities and utilities.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000001', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'text', '{"html":"<h3>Vector and raster data</h3><p>GIS holds two fundamental data models. <strong>Vector</strong> data represents discrete features as <strong>points, lines, and polygons</strong> &mdash; a monument as a point, a centerline as a line, a parcel as a polygon &mdash; each linked to attributes (owner, size, material, condition). Vector is the natural form for survey deliverables: precise, feature-based, and editable. <strong>Raster</strong> data represents the world as a <strong>grid of cells</strong>, each holding a value &mdash; an orthophoto, a DEM, a slope or land-cover surface. Raster is the natural form for continuous phenomena (elevation, imagery, temperature) and for analysis like slope, viewshed, and surface modeling. Most projects use both: vector parcels and utilities over a raster orthophoto and DEM.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000002', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'table', '{"headers":["Data model","Represents as","Best for"],"rows":[["Vector","Points, lines, polygons + attributes","Discrete features: parcels, monuments, utilities, roads"],["Raster","Grid of cells, one value each","Continuous data: imagery, DEM, slope, land cover"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000003', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'text', '{"html":"<h3>The surveyor as authoritative source</h3><p>A GIS is only as reliable as the data in it, and the <strong>surveyor is the authoritative source of accurate, control-tied geometry</strong>. Survey-grade monuments, boundaries, as-builts, and topographic features &mdash; positioned on a known datum to a documented accuracy &mdash; form the precise <em>backbone</em> on which less-rigorous GIS data are hung. The surveyor&rsquo;s contribution is not just coordinates but <strong>provenance and accuracy</strong>: data that can be trusted, traced to control, and certified where required. As local governments and utilities migrate records into GIS, the boundary between surveying and GIS is increasingly a handoff &mdash; the surveyor delivers rigorously positioned, attributed features, and the GIS integrates and serves them. Surveyors must understand GIS structure to deliver data that drops cleanly into it.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000004', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'text', '{"html":"<h3>Datums, projections, and matching coordinate systems</h3><p>The single most common GIS integration failure is a <strong>mismatch of spatial reference</strong>. Every layer carries a <strong>horizontal datum</strong> (e.g., NAD83), often a <strong>vertical datum</strong> (NAVD88), and a <strong>map projection / coordinate system</strong> (e.g., State Plane, UTM). Two layers will only overlay correctly if these match or are correctly transformed between. A parcel layer in State Plane feet and an orthophoto in UTM meters will not register until reprojected to a common system. Surveyors, who routinely work in State Plane coordinates with grid-to-ground scale factors, are well placed to manage these transformations &mdash; but must <strong>document the datum, epoch, projection, and units</strong> of every deliverable. That documentation is part of the <strong>metadata</strong>: the &lsquo;data about the data&rsquo; (source, accuracy, date, datum, method) that lets a GIS user know how the data may properly be used. Accurate geometry plus complete metadata is what makes a surveyor&rsquo;s product trustworthy in a GIS.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000005', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'callout', '{"type":"warning","text":"Spatial-reference discipline: layers overlay correctly only when their datum, projection, coordinate system, and units agree (or are properly transformed). Mixing State Plane feet with UTM meters, or NAD83 with NAD27, silently misplaces everything. Always state and verify the datum, epoch, projection, and units before integrating survey data into a GIS."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000006', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A GIS layer stack — vector parcels, utilities, and survey control over a raster orthophoto and DEM, all on a common spatial reference."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1910-0006-0000-0000-000000000007', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'key_takeaways', '{"title":"Key Takeaways","items":["A GIS organizes spatial data as layers of geometry plus attributes, in vector and raster forms.","Vector suits discrete features (parcels, utilities); raster suits continuous data (imagery, DEM).","Surveyors supply the authoritative, control-tied, documented-accuracy geometry a GIS depends on.","Layers must share a datum, coordinate system, projection, and units (or be transformed) to overlay.","Metadata — source, datum, projection, accuracy, date — is what makes survey data usable in a GIS."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000001', 'Topographic survey', 'A survey that records the existing ground — both planimetric features (horizontal position of objects) and relief (elevations/contours) — tied to horizontal and vertical control, to produce a base map for design.', 'Maps what exists: features + relief.', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000002', 'Radial (radiation) method', 'Locating detail points by direction and distance from an occupied control station — the natural mode of a total station or GNSS rover. The dominant modern topographic method.', 'Direction + distance from a control point.', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000003', 'Grid method', 'Reading elevations at the intersections of a regular square grid (plus grade breaks). Gives even coverage for contour interpolation and grid (borrow-pit) earthwork volumes; best on open, uniform ground.', 'Elevations at grid nodes.', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000004', 'Cross-section method', 'Taking offsets and elevations on lines perpendicular to a centerline at regular stations; the standard method for linear corridors (roads, channels) and average-end-area volumes.', 'Offsets normal to a centerline.', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000005', 'Contour line', 'A line on a map joining points of equal elevation — the shoreline the ground would have at that elevation. Together, a family of contours portrays the 3D shape of the land.', 'Line of constant elevation.', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000006', 'Contour interval', 'The constant vertical distance between adjacent contour lines (e.g., 1, 2, 5, or 10 ft). Chosen for terrain and map scale; flat/large-scale maps use small intervals.', 'Vertical spacing between contours.', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000007', 'Contour interpolation', 'Estimating an elevation between two known points by assuming a uniform slope: e = eA + (eB − eA)·d/D, where d/D is the proportional distance from A toward B.', 'Proportional distance along the line.', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000008', 'Index contour', 'Every fifth contour, drawn heavier and labeled with its elevation, to make a contour map easier to read and count.', 'Heavy, labeled every fifth line.', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000009', 'Saddle (pass)', 'A low point on a ridge between two summits, where contours form an hourglass pattern; the lowest crossing between higher ground on either side.', 'Low gap between two hills.', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000010', 'DTM / DEM', 'A Digital Terrain Model / Digital Elevation Model: a digital bare-earth surface. DEM commonly means a regular raster grid of elevations; DTM is the broader terrain model, often carrying breaklines.', 'Digital bare-earth surface.', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000011', 'DSM (Digital Surface Model)', 'A model of the first reflective surface — including building tops and tree canopy — as opposed to the bare-earth DTM/DEM. Used for line-of-sight and clearance studies.', 'First surface: includes buildings/trees.', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000012', 'TIN', 'A Triangulated Irregular Network — a mesh of triangles connecting the measured points, passing exactly through each one and adapting detail to point density. Honors points and breaklines for engineering surfaces.', 'Triangle mesh through the points.', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000013', 'Breakline', 'A line supplied with the points along which the surface is forced to change slope, so the model triangulates along (not across) ditches, ridges, curbs, and edges. Hard = grade break; soft = feature without a break.', 'Forces the surface to bend along a feature.', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000014', 'GNSS RTK', 'Real-time kinematic GNSS: a roving receiver positioned in real time against a base or network correction, giving centimeter-level coordinates fast in open sky. Degrades under canopy, near buildings, and in multipath.', 'Fast cm coords — needs sky view.', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000015', 'Feature code (descriptor)', 'A short code attached to each survey shot (e.g., EP, BC, FL, MH) that maps to a layer, symbol, and attributes in a code library, so the office software auto-draws the point on the correct layer.', 'Tells software what the point is.', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000016', 'Line-work / connectivity code', 'Codes (begin-line, end-line, continue, close, PC/PT, string numbers) that connect coded points into strings — curbs, edges, fences — which also become breaklines in the surface model.', 'Connects points into strings/breaklines.', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000017', 'Point cloud', 'A dense set of measured 3D points produced by LiDAR or photogrammetry, representing a surface or scene; must be registered to control and filtered (e.g., to bare earth) before use.', 'Millions of 3D points from scanning/imagery.', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000018', 'Map scale', 'The ratio of a distance on the map to the corresponding ground distance, given as a representative fraction (1:1200), an engineer''s scale (1 in. = 100 ft), or a graphic bar scale.', 'Map distance ÷ ground distance.', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000019', 'Large scale vs. small scale', 'Large scale (small denominator, e.g. 1:600) covers a small area in fine detail; small scale (large denominator, e.g. 1:24000) covers a large area with less detail.', 'Large scale = large detail, small area.', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000020', 'Graphic (bar) scale', 'A labeled ruler drawn on the map. Unlike a ratio or engineer''s scale, it remains correct when the map is photocopied, scanned, or resized.', 'The scale that survives copying.', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000021', 'ASPRS / NMAS accuracy standards', 'Mapping accuracy standards. NMAS ties horizontal/vertical tolerances to map scale and contour interval; the modern ASPRS Positional Accuracy Standards state accuracy as RMSE, independent of paper scale, for digital data.', 'How much to trust a mapped position.', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000022', 'GIS (Geographic Information System)', 'Software and data for capturing, storing, analyzing, and displaying spatially referenced information as layers of geometry joined to attribute tables, supporting spatial query and analysis.', 'Layers of geometry + attributes.', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000023', 'Vector vs. raster', 'Vector data represents discrete features as points, lines, and polygons with attributes (parcels, utilities); raster data represents continuous phenomena as a grid of cells (imagery, DEM, slope).', 'Features vs. grid of cells.', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000024', 'Spatial reference / projection', 'The datum, coordinate system, projection, and units that locate a layer in space (e.g., NAD83 / State Plane, NAVD88). Layers must share these — or be transformed — to overlay correctly.', 'Datum + projection + units must match.', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1940-0000-0000-0000-000000000025', 'Metadata', '''Data about the data'': documented source, datum, projection, units, accuracy, method, and date of a dataset, which tells a GIS user how the data may properly be used and trusted.', 'Provenance and accuracy of the data.', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', 'surveying', ARRAY['buildout','module-19']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000001', 'What does a topographic survey primarily produce, in contrast to a boundary survey?', 'multiple_choice', '["A base map of existing planimetric features and relief (elevations/contours)","A legal description of the property''s perimeter only","A recorded plat of newly created lot lines","A title commitment listing encumbrances"]'::jsonb, 'A base map of existing planimetric features and relief (elevations/contours)', 'A topographic survey maps what exists — planimetric detail and relief — as a base map for design. A boundary survey produces property lines; legal descriptions and title work are separate products.', 'easy', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000002', 'Which topographic survey method locates each detail point by direction and distance from an occupied control station?', 'multiple_choice', '["Radial (radiation) method","Grid method","Cross-section method","Plane-table method"]'::jsonb, 'Radial (radiation) method', 'Radiation locates points by direction and distance from an occupied station — the natural mode of a total station or GNSS rover. The grid uses a fixed pattern of nodes, and cross-sections use offsets normal to a centerline.', 'easy', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000003', 'For a linear corridor project such as a road or channel, which data-collection method is most appropriate?', 'multiple_choice', '["Cross-section method","Grid method","Closed-traverse method","Resection method"]'::jsonb, 'Cross-section method', 'Cross-sectioning takes elevations on lines perpendicular to a centerline at stations, organizing data by station and offset — ideal for corridors and average-end-area volumes. The grid suits open areas, not linear work.', 'medium', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000004', 'Detail (ground) points in a topographic survey may be located by measuring from one detail point to the next to save time.', 'true_false', '["True","False"]'::jsonb, 'False', 'Detail points are always located from established control, never chained from one detail point to the next, so that error does not accumulate across the map.', 'medium', 'c1000013-0000-0000-0000-000000000013', 'f154fdbd-1aec-4c41-a6a8-a7f67b40a53a', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000005', 'Closely spaced contour lines on a topographic map indicate:', 'multiple_choice', '["A steep slope","A gentle slope","Flat ground","A depression"]'::jsonb, 'A steep slope', 'Contour spacing represents slope: closely spaced contours mean the ground rises quickly (steep), while widely spaced contours mean gentle ground.', 'easy', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000006', 'On a contour map, where a contour crosses a stream it forms a V. Which way does the point of the V face?', 'multiple_choice', '["Upstream (uphill)","Downstream (downhill)","Always due north","Toward the nearest index contour"]'::jsonb, 'Upstream (uphill)', 'Contours crossing a valley or stream form a V that points upstream (uphill). On a ridge, the contour''s nose points downhill — the opposite case.', 'medium', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000007', 'Point A is at elevation 612.0 ft and point B at 620.0 ft, 80 ft apart. By linear interpolation, the elevation 30 ft from A toward B is:', 'multiple_choice', '["615.0 ft","616.0 ft","613.0 ft","618.0 ft"]'::jsonb, '615.0 ft', 'e = eA + (eB − eA)·d/D = 612.0 + (620.0 − 612.0)×30/80 = 612.0 + 8.0×0.375 = 615.0 ft.', 'medium', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000008', 'At a 5-ft contour interval, how many contour lines fall between 643 ft and 678 ft?', 'multiple_choice', '["7","6","8","35"]'::jsonb, '7', 'n = floor((678 − 643)/5) = floor(35/5) = 7 (the contours 645, 650, 655, 660, 665, 670, 675).', 'medium', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000009', 'A set of closed contours marked with short hachure ticks pointing inward, with values decreasing toward the center, represents a summit (hill).', 'true_false', '["True","False"]'::jsonb, 'False', 'Inward-pointing hachure ticks with decreasing values mark a depression, not a summit. A summit is shown by concentric closed contours that increase toward the center, without hachures.', 'medium', 'c1000013-0000-0000-0000-000000000013', '99ca2a92-e87b-493f-bb7c-1cae6d4dd950', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000010', 'What is the key difference between a DEM/DTM (bare earth) and a DSM?', 'multiple_choice', '["A DSM includes the first reflective surface (buildings, tree canopy); the DTM/DEM is bare earth","A DSM is always more accurate than a DTM","A DEM stores attributes while a DSM stores only geometry","A DTM is raster and a DSM is always a TIN"]'::jsonb, 'A DSM includes the first reflective surface (buildings, tree canopy); the DTM/DEM is bare earth', 'A DSM represents the first reflective surface — building tops and canopy — whereas the DTM/DEM represents the bare-earth ground. Design and drainage use the bare-earth model.', 'medium', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000011', 'Which surface structure connects the measured points themselves into a mesh of triangles that passes exactly through each point?', 'multiple_choice', '["TIN (Triangulated Irregular Network)","Raster grid DEM","Contour overlay","Orthophoto mosaic"]'::jsonb, 'TIN (Triangulated Irregular Network)', 'A TIN triangulates the measured points so the surface passes exactly through each one and adapts detail to point density. A raster DEM resamples elevations onto regular cells.', 'medium', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000012', 'What is the purpose of a breakline in a surface model?', 'multiple_choice', '["To force the surface to bend along a linear grade break instead of triangulating across it","To delete erroneous points automatically","To label the contour interval on the map","To convert a TIN into an orthophoto"]'::jsonb, 'To force the surface to bend along a linear grade break instead of triangulating across it', 'A breakline forces the triangulation along a feature — a ditch, ridge, curb, or edge — so the surface honors the real grade break rather than smoothing across it.', 'easy', 'c1000013-0000-0000-0000-000000000013', '09a9602d-40c0-42c4-a2ad-bba213dcc715', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000013', 'Which data-collection technology works best under dense tree canopy where satellite signals are blocked?', 'multiple_choice', '["Total station","GNSS RTK rover","UAS photogrammetry","Static GNSS"]'::jsonb, 'Total station', 'A total station measures direction and distance to a prism and does not depend on satellites, so it excels under canopy and around structures. GNSS methods degrade or fail without a clear sky view.', 'easy', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000014', 'What is the primary function of a feature (descriptor) code attached to a survey shot?', 'multiple_choice', '["To map the point to a layer, symbol, and attributes so the office software auto-draws it","To increase the GNSS accuracy of the point","To store the instrument''s battery level","To encrypt the coordinate for security"]'::jsonb, 'To map the point to a layer, symbol, and attributes so the office software auto-draws it', 'A feature code identifies what the point is and maps it (via the code library) to a layer, symbol, and attributes, so the drawing assembles automatically rather than being drafted point by point.', 'medium', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000015', 'GNSS RTK gives fast, centimeter-level coordinates and is unaffected by tree canopy or nearby tall buildings.', 'true_false', '["True","False"]'::jsonb, 'False', 'RTK is fast and centimeter-level in the open, but it degrades or fails under canopy and near tall buildings due to blocked signals and multipath. A total station is preferred there.', 'medium', 'c1000013-0000-0000-0000-000000000013', '384ced07-ed6b-46b9-88b7-b262a9524398', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000016', 'A map is drawn at an engineer''s scale of 1 in. = 50 ft. A 450-ft distance plots on the map as:', 'multiple_choice', '["9.0 in.","4.5 in.","90 in.","0.9 in."]'::jsonb, '9.0 in.', 'map distance (in.) = ground (ft) × 12 / S = 450 × 12 / 50 = 5400/50 = 9.0 in.', 'medium', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000017', 'Which map is the LARGER-scale map?', 'multiple_choice', '["1:600 (1 in. = 50 ft)","1:24000","1:100000","1:1,000,000"]'::jsonb, '1:600 (1 in. = 50 ft)', 'The smaller the scale denominator, the larger the scale. 1:600 covers a small area in fine detail (large scale); 1:24000 and smaller cover large areas with less detail.', 'medium', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000018', 'Which scale form remains correct after a map sheet is photocopied or resized?', 'multiple_choice', '["The graphic (bar) scale","The representative fraction (ratio)","The engineer''s scale statement","The verbal scale note"]'::jsonb, 'The graphic (bar) scale', 'A graphic bar scale is drawn on the map, so it scales up or down with the sheet and stays correct. A ratio or stated scale becomes wrong once the sheet is enlarged or reduced.', 'easy', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000019', 'Which standard expresses positional accuracy directly as RMSE values, independent of a paper map scale, for digital geospatial data?', 'multiple_choice', '["ASPRS Positional Accuracy Standards for Digital Geospatial Data","National Map Accuracy Standards (NMAS) of 1947","The Public Land Survey System (PLSS)","The Manual of Surveying Instructions"]'::jsonb, 'ASPRS Positional Accuracy Standards for Digital Geospatial Data', 'The ASPRS standards state accuracy as RMSE, independent of paper scale, and are used for digital orthophotos, LiDAR, and DEMs. NMAS ties tolerances to map scale and contour interval.', 'hard', 'c1000013-0000-0000-0000-000000000013', 'be27f689-8827-43fc-8fdd-f015d2d8b369', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000020', 'In a GIS, which data model represents discrete features such as parcels and utilities as points, lines, and polygons with attributes?', 'multiple_choice', '["Vector","Raster","TIN","Orthophoto"]'::jsonb, 'Vector', 'Vector data represents discrete features as points, lines, and polygons joined to attributes. Raster represents continuous phenomena as a grid of cells (imagery, DEM).', 'easy', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000021', 'Why must all layers in a GIS share a common datum, coordinate system, and projection (or be transformed)?', 'multiple_choice', '["So the layers overlay (register) in the correct relative positions","So the files are smaller on disk","So the attributes are encrypted consistently","So the map automatically meets NMAS accuracy"]'::jsonb, 'So the layers overlay (register) in the correct relative positions', 'Layers only register correctly when their spatial reference matches or is properly transformed. Mixing State Plane feet with UTM meters, or NAD83 with NAD27, silently misplaces features.', 'medium', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000022', 'What is the surveyor''s principal contribution to a GIS?', 'multiple_choice', '["Authoritative, control-tied geometry with documented accuracy and metadata","The cartographic color scheme for the basemap","The server hardware that hosts the layers","The web interface used to query the data"]'::jsonb, 'Authoritative, control-tied geometry with documented accuracy and metadata', 'Surveyors supply the precise, control-tied geometry — boundaries, monuments, as-builts, topography — on a known datum with documented accuracy and metadata, forming the trusted backbone of the GIS.', 'medium', 'c1000013-0000-0000-0000-000000000013', '4c291d33-27fd-44ec-aa26-a2af9ed63b8b', ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1930-0000-0000-0000-000000000023', 'Define ''metadata'' as it applies to a survey dataset delivered to a GIS.', 'short_answer', '[]'::jsonb, 'Data about the data — documented source, datum, projection, units, accuracy, method, and date — that tells the user how the dataset may properly be used.', 'Metadata is the documented provenance and accuracy of a dataset (source, datum, projection, units, accuracy, method, date). It lets a GIS user know how the data may properly be used and trusted.', 'medium', 'c1000013-0000-0000-0000-000000000013', NULL, ARRAY['buildout','module-19']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1960-0000-0000-0000-000000000001', 'Point A has elevation {{eA:f2}} ft and point B has elevation {{eB:f2}} ft. The horizontal distance from A to B is {{D}} ft. Assuming a uniform slope, what is the elevation (ft) of a point located {{d}} ft from A toward B?', 'numeric_input', '[]'::jsonb, '0', 'Linear interpolation: e = eA + (eB − eA)·d/D = {{eA:f2}} + ({{eB:f2}} − {{eA:f2}}) × {{d}} ÷ {{D}} = {{_answer}} ft.', 'medium', 'c1000013-0000-0000-0000-000000000013', NULL, ARRAY['buildout','module-19','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1950-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1960-0000-0000-0000-000000000002', 'A slope rises from an elevation of {{eLow}} ft to {{eHigh}} ft. If the contour interval is {{interval}} ft, how many contour lines are crossed between these two elevations?', 'numeric_input', '[]'::jsonb, '0', 'n = floor((eHigh − eLow)/interval) = floor(({{eHigh}} − {{eLow}}) ÷ {{interval}}) = {{_answer}} contour lines.', 'easy', 'c1000013-0000-0000-0000-000000000013', NULL, ARRAY['buildout','module-19','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1950-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1960-0000-0000-0000-000000000003', 'A map is drawn at an engineer''s scale of 1 in. = {{scale}} ft. What is the plotted map distance (inches) for a ground distance of {{groundDist}} ft?', 'numeric_input', '[]'::jsonb, '0', 'Map distance (in.) = ground distance (ft) × 12 ÷ scale = {{groundDist}} × 12 ÷ {{scale}} = {{_answer}} in.', 'easy', 'c1000013-0000-0000-0000-000000000013', NULL, ARRAY['buildout','module-19','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1950-0000-0000-0000-000000000003', 0.02);
